   371→
   372→### Epic: Authentication & Security
   373→**Story Points: 6**
   374→
   375→#### SEC-001: OAuth2 PKCE Flow (Studio ↔ Keycloak)
   376→**Points: 4 | Priority: High**
   377→
   378→**Description:** Implement secure authentication flow for researcher access to Forge Studio.
   379→
   380→**Technical Requirements:**
   381→- OAuth2 Authorization Code flow with PKCE for security
   382→- Keycloak integration for identity management
   383→- JWT token handling with automatic refresh
   384→- Role-based access control (admin, researcher, viewer)
   385→- Multi-factor authentication support
   386→
   387→**Acceptance Criteria:**
   388→- [ ] OAuth2 PKCE flow implemented correctly and securely
   389→- [ ] Keycloak integration handles user authentication
   390→- [ ] JWT tokens automatically refreshed before expiration
   391→- [ ] Role-based permissions control access to features
   392→- [ ] MFA supported for enhanced security
   393→- [ ] Security audit passes all authentication tests
   394→
   395→**Authentication Implementation:**
   396→```typescript
   397→// @psyforge/auth
   398→export class AuthenticationManager {
   399→  private keycloakClient: KeycloakClient;
   400→  private tokenManager: TokenManager;
   401→  
   402→  constructor(config: AuthConfig) {
   403→    this.keycloakClient = new KeycloakClient(config.keycloak);
   404→    this.tokenManager = new TokenManager();
   405→  }
   406→  
   407→  // Initialize OAuth2 PKCE flow
   408→  async initiateLogin(): Promise<AuthorizationUrl> {
   409→    const codeVerifier = this.generateCodeVerifier();
   410→    const codeChallenge = await this.generateCodeChallenge(codeVerifier);
   411→    
   412→    // Store PKCE parameters
   413→    this.tokenManager.storePKCEParams(codeVerifier);
   414→    
   415→    const authUrl = this.keycloakClient.getAuthorizationUrl({
   416→      client_id: 'psyforge-studio',
   417→      redirect_uri: `${window.location.origin}/auth/callback`,
   418→      scope: 'openid profile email',
   419→      response_type: 'code',
   420→      code_challenge: codeChallenge,
   421→      code_challenge_method: 'S256'
   422→    });
   423→    
   424→    return authUrl;
   425→  }
   426→  
   427→  // Handle OAuth callback
   428→  async handleCallback(authorizationCode: string): Promise<AuthenticationResult> {
   429→    const codeVerifier = this.tokenManager.getPKCEVerifier();
   430→    
   431→    const tokens = await this.keycloakClient.exchangeCodeForTokens({
   432→      code: authorizationCode,
   433→      code_verifier: codeVerifier,
   434→      client_id: 'psyforge-studio',
   435→      redirect_uri: `${window.location.origin}/auth/callback`
   436→    });
   437→    
   438→    // Validate and store tokens
   439→    const userInfo = await this.validateTokens(tokens);
   440→    this.tokenManager.storeTokens(tokens);
   441→    
   442→    return {
   443→      user: userInfo,
   444→      permissions: this.extractPermissions(tokens.access_token),
   445→      expiresAt: tokens.expires_at
   446→    };
   447→  }
   448→  
   449→  // Automatic token refresh
   450→  async refreshTokensIfNeeded(): Promise<boolean> {
   451→    if (!this.tokenManager.needsRefresh()) {
   452→      return false;
   453→    }
   454→    
   455→    try {
   456→      const refreshToken = this.tokenManager.getRefreshToken();
   457→      const newTokens = await this.keycloakClient.refreshTokens(refreshToken);
   458→      
   459→      this.tokenManager.storeTokens(newTokens);
   460→      return true;
   461→    } catch (error) {
   462→      // Refresh failed, require re-authentication
   463→      this.tokenManager.clearTokens();
   464→      throw new AuthenticationRequiredError();
   465→    }
   466→  }
   467→}
   468→
   469→// Role-based access control
   470→export interface UserPermissions {
   471→  canCreateExperiments: boolean;
   472→  canPublishExperiments: boolean;
   473→  canAccessAnalytics: boolean;
   474→  canManageUsers: boolean;
   475→  maxParticipants: number;
   476→  allowedProviders: string[];
   477→}
   478→
   479→export function hasPermission(user: AuthenticatedUser, permission: keyof UserPermissions): boolean {
   480→  return user.permissions[permission] === true;
   481→}
   482→```
