**ForgeRouter Implementation:**
```typescript
// @psyforge/forge-router
import Fastify from 'fastify';
import jwt from '@fastify/jwt';
import { DatabaseManager } from './database';
import { ExperimentAssigner } from './assignment';

export class ForgeRouter {
  private server: Fastify.FastifyInstance;
  private db: DatabaseManager;
  private assigner: ExperimentAssigner;

  constructor() {
    this.server = Fastify({ logger: true });
    this.setupRoutes();
    this.setupMiddleware();
  }

  private setupRoutes(): void {
    // Main participant entry point
    this.server.get('/router/:studyId', this.handleParticipantEntry.bind(this));

    // Health check and status endpoints
    this.server.get('/health', this.healthCheck.bind(this));
    this.server.get('/status/:sessionId', this.getSessionStatus.bind(this));
  }

  async handleParticipantEntry(request: FastifyRequest, reply: FastifyReply) {
    const { studyId } = request.params;
    const providerParams = request.query; // PROLIFIC_PID, MTURK_ID, etc.

    try {
      // Start database transaction for atomic assignment
      await this.db.transaction(async (tx) => {
        // Load study configuration
        const study = await this.loadStudy(studyId, tx);

        // Execute assignment logic (counter, latin square, etc.)
        const assignment = await this.assigner.assignCondition(
          study, 
          providerParams, 
          tx
        );

        // Generate session JWT
        const sessionToken = await this.generateSessionToken({
          participantId: assignment.participantId,
          studyId: studyId,
          studyVersion: study.version,
          conditionLevels: assignment.conditions,
          provider: this.detectProvider(providerParams),
          assignedAt: new Date().toISOString()
        });

        // Redirect to experiment runner
        const runnerUrl = `${study.runnerBaseUrl}?session=${sessionToken}`;
        reply.redirect(302, runnerUrl);
      });

    } catch (error) {
      this.handleRoutingError(error, reply);
    }
  }

  private async generateSessionToken(claims: SessionClaims): Promise<string> {
    return this.server.jwt.sign(claims, {
      expiresIn: '24h', // Reasonable time for experiment completion
      issuer: 'psyforge-router',
      audience: 'psyforge-runner'
    });
  }
}

export interface SessionClaims {
  participantId: string;
  studyId: string;
  studyVersion: string;
  conditionLevels: Record<string, any>;
  provider: 'prolific' | 'mturk' | 'sona' | 'direct';
  assignedAt: string;
}
```

#### SRV-002: Global State DB & Transactional Logic
**Points: 3 | Priority: Critical**

**Description:** Implement database layer with ACID transactions for condition assignment and global counters.

**Technical Requirements:**
- PostgreSQL with SERIALIZABLE isolation level for critical sections
- Global counter management with atomic increment operations
