   362→
   363→**DAL Interface Design:**
   364→```typescript
   365→// @psyforge/dal
   366→export interface Device {
   367→  readonly deviceId: string;
   368→  readonly deviceName: string;
   369→  readonly deviceType: DeviceType;
   370→  readonly capabilities: DeviceCapabilities;
   371→  readonly isConnected: boolean;
   372→  
   373→  // Lifecycle methods
   374→  connect(): Promise<void>;
   375→  disconnect(): Promise<void>;
   376→  calibrate?(): Promise<CalibrationResult>;
   377→  
   378→  // Event handling
   379→  on<T extends DeviceEvent>(event: string, listener: (data: T) => void): this;
   380→  off(event: string, listener: Function): this;
   381→  emit(event: string, data: any): void;
   382→  
   383→  // Device status
   384→  getStatus(): DeviceStatus;
   385→  getCapabilities(): DeviceCapabilities;
   386→}
   387→
   388→// Input devices (keyboards, mice, response boxes)
   389→export interface InputDevice extends Device {
   390→  readonly deviceType: 'input';
   391→  
   392→  // Common input events
   393→  on(event: 'keypress', listener: (data: KeyPressEvent) => void): this;
   394→  on(event: 'buttonpress', listener: (data: ButtonPressEvent) => void): this;
   395→  on(event: 'mouseclick', listener: (data: MouseClickEvent) => void): this;
   396→}
   397→
   398→// Physiological monitoring devices
   399→export interface PhysiologicalDevice extends Device {
   400→  readonly deviceType: 'physiological';
   401→  readonly samplingRate: number;
   402→  
   403→  startRecording(): Promise<void>;
   404→  stopRecording(): Promise<RecordingData>;
   405→  
   406→  on(event: 'sample', listener: (data: PhysiologicalSample) => void): this;
   407→  on(event: 'artifact', listener: (data: ArtifactEvent) => void): this;
   408→}
   409→
   410→// EEG-specific interface
   411→export interface EEGDevice extends PhysiologicalDevice {
   412→  readonly channels: number;
   413→  readonly impedanceThreshold: number;
   414→  
   415→  checkImpedance(): Promise<ImpedanceReadings>;
   416→  setReference(reference: EEGReference): Promise<void>;
   417→  sendTrigger(code: number, timestamp?: number): Promise<void>;
   418→}
   419→
   420→// Eye tracking interface
   421→export interface EyeTracker extends PhysiologicalDevice {
   422→  readonly trackingMode: 'monocular' | 'binocular';
   423→  readonly accuracy: number; // degrees visual angle
   424→  
   425→  calibrate(points: CalibrationPoint[]): Promise<CalibrationResult>;
   426→  startValidation(): Promise<ValidationResult>;
   427→  
   428→  on(event: 'gaze', listener: (data: GazeEvent) => void): this;
   429→  on(event: 'fixation', listener: (data: FixationEvent) => void): this;
   430→  on(event: 'saccade', listener: (data: SaccadeEvent) => void): this;
   431→}
   432→
   433→// Response box interface (Cedrus, Psychology Software Tools)
   434→export interface ResponseBox extends InputDevice {
   435→  readonly buttonCount: number;
   436→  readonly hasLights: boolean;
   437→  
   438→  setButtonLight(button: number, state: boolean): Promise<void>;
   439→  
   440→  on(event: 'buttonpress', listener: (data: ButtonPressEvent) => void): this;
   441→  on(event: 'buttonrelease', listener: (data: ButtonReleaseEvent) => void): this;
   442→}
   443→
   444→// Device registry and discovery
   445→export class DeviceRegistry {
   446→  private devices = new Map<string, Device>();
   447→  private drivers = new Map<string, DeviceDriver>();
   448→  
   449→  // Register device driver
   450→  registerDriver(driver: DeviceDriver): void {
   451→    this.drivers.set(driver.deviceType, driver);
   452→  }
   453→  
   454→  // Discover available devices
   455→  async discoverDevices(): Promise<Device[]> {
   456→    const discoveredDevices: Device[] = [];
   457→    
   458→    for (const driver of this.drivers.values()) {
   459→      try {
   460→        const devices = await driver.discover();
   461→        discoveredDevices.push(...devices);
   462→      } catch (error) {
   463→        console.warn(`Device discovery failed for ${driver.deviceType}:`, error);
   464→      }
   465→    }
   466→    
   467→    return discoveredDevices;
   468→  }
   469→  
   470→  // Get device by ID
   471→  getDevice(deviceId: string): Device | undefined {
   472→    return this.devices.get(deviceId);
   473→  }
   474→  
   475→  // Get devices by type
   476→  getDevicesByType<T extends Device>(type: DeviceType): T[] {
   477→    return Array.from(this.devices.values())
   478→      .filter(device => device.deviceType === type) as T[];
   479→  }
   480→}
   481→
   482→export interface DeviceDriver {
   483→  readonly deviceType: string;
   484→  readonly supportedModels: string[];
   485→  
   486→  // Discover devices of this type
   487→  discover(): Promise<Device[]>;
   488→  
   489→  // Create device instance
   490→  createDevice(config: DeviceConfig): Promise<Device>;
   491→}
