}

// components/ExperimentSearch.tsx
export function ExperimentSearch() {
  const [query, setQuery] = useState('');
  const [filters, setFilters] = useState<SearchFilters>({});
  const [results, setResults] = useState<ExperimentSearchResult[]>([]);

  const searchExperiments = useCallback(
    debounce(async (searchQuery: string, searchFilters: SearchFilters) => {
      const results = await hubClient.searchExperiments({
        query: searchQuery,
        ...searchFilters
      });
      setResults(results);
    }, 300),
    []
  );

  return (
    <div className="experiment-search">
      <div className="search-header bg-gray-50 p-6 rounded-lg mb-6">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <input
              type="text"
              placeholder="Search experiments..."
              value={query}
              onChange={(e) => {
                setQuery(e.target.value);
                searchExperiments(e.target.value, filters);
              }}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>

          <SearchFilters 
            filters={filters}
            onChange={(newFilters) => {
              setFilters(newFilters);
              searchExperiments(query, newFilters);
            }}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {results.map(experiment => (
          <ExperimentCard
            key={experiment.id}
            experiment={experiment}
            onFork={handleFork}
            onStar={handleStar}
          />
        ))}
