// @psyforge/collaboration
import * as Y from 'yjs';
import { WebrtcProvider } from 'y-webrtc';
import { WebsocketProvider } from 'y-websocket';

export class ExperimentCRDT {
  private doc: Y.Doc;
  private experimentMap: Y.Map<any>;
