// @psyforge/timing
export class TimingDriftDetector {
  private expectedInterval: number;
  private actualIntervals: number[] = [];
  private warningThreshold: number = 2; // ms

  detectDrift(): TimingDriftReport {
    const avgDrift = this.calculateAverageDrift();
    const isThrottled = this.detectThrottling();
    const osInterference = this.detectOSInterference();

    return {
      avgDrift,
      isThrottled,
      osInterference,
      recommendation: this.getRecommendation(avgDrift, isThrottled)
    };
  }

  private detectThrottling(): boolean {
    // Detect background tab throttling
    return document.hidden || this.getAverageInterval() > this.expectedInterval * 1.5;
  }

  private detectOSInterference(): boolean {
    // Detect OS power management or high system load
    const variance = this.calculateVariance();
    return variance > this.warningThreshold;
  }
}
