**Prolific Integration Implementation:**
```typescript
// @psyforge/recruit-bridge
export interface RecruitmentProvider {
  readonly name: string;

  // Create study on platform
  createStudy(config: StudyConfig): Promise<ExternalStudyId>;

  // Update study parameters
  updateStudy(externalId: ExternalStudyId, config: Partial<StudyConfig>): Promise<void>;

  // Publish study to start recruitment
  publishStudy(externalId: ExternalStudyId): Promise<void>;

  // Handle study completion and payments
  completeStudy(externalId: ExternalStudyId): Promise<void>;

  // Process individual participant completion
  approveSubmission(externalId: ExternalStudyId, participantId: string): Promise<void>;

  // Send bonus payments
  bonusPayment(externalId: ExternalStudyId, participantId: string, amount: number): Promise<void>;
}

export class ProlificProvider implements RecruitmentProvider {
  readonly name = 'prolific';

  private apiClient: ProlificAPIClient;

  constructor(apiKey: string, sandbox = false) {
    this.apiClient = new ProlificAPIClient(apiKey, sandbox);
  }

  async createStudy(config: StudyConfig): Promise<string> {
    // Map ForgeScript recruitment config to Prolific study format
    const prolificStudy = {
      name: config.name,
      description: config.description,
      external_study_url: config.studyUrl,
      prolific_id_option: 'url_parameters', // Pass PROLIFIC_PID in URL
      completion_code: config.completionCode,
      completion_option: 'redirect',
      total_available_places: config.targetParticipants,
      reward: config.compensation.base, // In pence for GBP
      estimated_completion_time: config.estimatedDuration,

      // Map screening criteria
      eligibility_requirements: this.mapScreeningCriteria(config.criteria)
    };

    const response = await this.apiClient.post('/studies/', prolificStudy);
    return response.id;
  }

  private mapScreeningCriteria(criteria: ScreeningCriteria): ProlificEligibilityRequirement[] {
    const requirements: ProlificEligibilityRequirement[] = [];

    // Age requirements
    if (criteria.age) {
      requirements.push({
        _cls: 'web.eligibility.models.AgeRangeEligibilityRequirement',
        min_age: criteria.age.min,
        max_age: criteria.age.max
      });
    }

    // Language requirements
    if (criteria.language) {
      requirements.push({
        _cls: 'web.eligibility.models.LanguageEligibilityRequirement',
        language: this.mapLanguageCode(criteria.language)
      });
    }

    // Custom screening questions
    if (criteria.customScreening) {
      criteria.customScreening.forEach(screen => {
        requirements.push({
          _cls: 'web.eligibility.models.CustomEligibilityRequirement',
          question: screen.question,
          accepted_answers: screen.acceptedAnswers
        });
      });
    }

    return requirements;
  }
}

// Provider registry and factory
export class RecruitmentProviderRegistry {
  private providers = new Map<string, () => RecruitmentProvider>();

  register(name: string, factory: () => RecruitmentProvider): void {
    this.providers.set(name, factory);
  }

  create(name: string): RecruitmentProvider {
    const factory = this.providers.get(name);
    if (!factory) {
      throw new Error(`Unknown recruitment provider: ${name}`);
    }
    return factory();
  }
}

// Pre-registered providers
export const recruitmentProviders = new RecruitmentProviderRegistry();
recruitmentProviders.register('prolific', () => 
  new ProlificProvider(process.env.PROLIFIC_API_KEY!, process.env.NODE_ENV !== 'production')
);
```

#### URF-002: Provider-Meta Registry
**Points: 3 | Priority: Medium**

**Description:** Build dynamic registry system for recruitment provider capabilities and screening attributes.

**Technical Requirements:**
- Automated scraping of provider API documentation
- Versioned schema storage for provider attributes
- Dynamic UI generation for screening criteria
- Provider capability comparison and selection assistance

**Acceptance Criteria:**
- [ ] Provider capabilities automatically detected and stored
- [ ] Screening attribute schemas updated from provider APIs
- [ ] UI dynamically generates screening criteria forms
