- [ ] Schema versioning handles provider API changes gracefully

**Provider Registry Implementation:**
```typescript
// @psyforge/provider-meta
export interface ProviderCapabilities {
  name: string;
  version: string;
  supportedFeatures: string[];
  prescreeningAttributes: AttributeSchema[];
  compensationModel: CompensationSchema;
  maxParticipants: number;
  geographicRestrictions: string[];
}

export class ProviderMetaRegistry {
  private capabilities = new Map<string, ProviderCapabilities>();

  async updateProviderCapabilities(provider: string): Promise<void> {
    const capabilities = await this.scrapeProviderAPI(provider);
    this.capabilities.set(provider, capabilities);
  }

  getCompatibleProviders(requirements: StudyRequirements): ProviderCapabilities[] {
    return Array.from(this.capabilities.values())
      .filter(provider => this.isCompatible(provider, requirements));
  }

  private async scrapeProviderAPI(provider: string): Promise<ProviderCapabilities> {
    // Provider-specific API documentation scraping
    switch (provider) {
      case 'prolific':
        return this.scrapeProlificAPI();
      default:
        throw new Error(`Unknown provider: ${provider}`);
    }
  }
}
```

