**Hub API Integration:**
```typescript
// @psyforge/hub-client
export class ForgeHubClient {
  private giteaClient: GiteaAPIClient;
  private auth: AuthenticationManager;

  constructor(config: HubConfig) {
    this.giteaClient = new GiteaAPIClient(config.baseUrl, config.apiToken);
    this.auth = new AuthenticationManager(config.auth);
  }

  // Publish experiment to Hub
  async publishExperiment(experiment: CompiledExperiment, metadata: ExperimentMetadata): Promise<HubRepository> {
    // Create repository
    const repo = await this.giteaClient.createRepository({
      name: this.generateRepositoryName(experiment.name),
      description: metadata.description,
      private: metadata.private || false,
      license: 'CC-BY-4.0', // Default for scientific content
      template: 'psyforge-experiment-template'
    });

    // Upload experiment files
    await this.uploadExperimentFiles(repo, experiment, metadata);

    // Generate DOI if public
    if (!metadata.private) {
      const doi = await this.generateDOI(repo, metadata);
      await this.updateRepositoryMetadata(repo, { doi });
    }

    return repo;
  }

  // Search experiments by criteria
  async searchExperiments(criteria: SearchCriteria): Promise<ExperimentSearchResult[]> {
    const searchQuery = this.buildSearchQuery(criteria);
    const results = await this.giteaClient.searchRepositories(searchQuery);

    return results.map(repo => ({
      id: repo.id,
      name: repo.name,
      description: repo.description,
      author: repo.owner.login,
      stars: repo.stars_count,
      forks: repo.forks_count,
      lastUpdated: repo.updated_at,
      tags: this.extractTags(repo.topics),
      doi: this.extractDOI(repo.description),
      citationCount: this.getCitationCount(repo.id)
    }));
  }

  // Fork experiment for modification
  async forkExperiment(originalId: string, newName?: string): Promise<HubRepository> {
    const fork = await this.giteaClient.forkRepository(originalId, {
      name: newName
    });

    // Update fork metadata
    await this.updateForkMetadata(fork, originalId);

    return fork;
  }
}

export interface ExperimentMetadata {
  title: string;
  description: string;
  authors: Author[];
  tags: string[];
  category: ExperimentCategory;
  difficulty: 'beginner' | 'intermediate' | 'advanced';
  estimatedDuration: number; // minutes
  requiredDevices: string[];
  private: boolean;
  license: string;
}
