```typescript
// paradigms/stroop-task.ts
export const StroopTask = new ExperimentTemplate({
  name: 'Stroop Color-Word Interference Task',
  version: '1.0.0',
  citation: 'Stroop, J. R. (1935). Studies of interference in serial verbal reactions. Journal of Experimental Psychology, 18(6), 643-662.',
  doi: '10.1037/h0054651',

  description: `
    The classic Stroop task measuring color-word interference effects.
    Participants name the ink color of color words, which may be congruent
    (word RED in red ink) or incongruent (word RED in blue ink).
  `,

  parameters: {
    practiceTrials: {
      type: 'number',
      default: 10,
      min: 0,
      max: 50,
      description: 'Number of practice trials before main experiment'
    },

    testTrials: {
      type: 'number', 
      default: 100,
      min: 20,
      max: 500,
      description: 'Number of test trials in main experiment'
    },

    stimulusDuration: {
      type: 'number',
      default: 1500,
      min: 500,
      max: 5000,
      unit: 'ms',
      description: 'Duration of stimulus presentation'
    },

    responseTimeout: {
      type: 'number',
      default: 2000,
      min: 1000,
      max: 10000,
      unit: 'ms',
      description: 'Maximum time allowed for response'
    },

    congruentProportion: {
      type: 'number',
      default: 0.5,
      min: 0.1,
      max: 0.9,
      description: 'Proportion of congruent trials (0.5 = equal congruent/incongruent)'
    }
  },

  generate(params: StroopParameters): CompiledExperiment {
    const colors = ['red', 'green', 'blue', 'yellow'];
    const words = ['RED', 'GREEN', 'BLUE', 'YELLOW'];
    const keys = ['r', 'g', 'b', 'y'];

    return new Experiment({ name: 'Stroop Task' })
      .addTimeline(
        new Timeline({ id: 'instructions' })
          .addTrial(createInstructionTrial())
      )
      .addTimeline(
        new Timeline({ id: 'practice' })
          .addTrials(generateStroopTrials({
            colors, words, keys,
            nTrials: params.practiceTrials,
            congruentProp: 0.5, // Balanced practice
            stimulusDuration: params.stimulusDuration,
            responseTimeout: params.responseTimeout
          }))
          .setRandomization({ method: 'shuffle' })
      )
      .addTimeline(
        new Timeline({ id: 'main_experiment' })
          .addTrials(generateStroopTrials({
            colors, words, keys,
            nTrials: params.testTrials,
            congruentProp: params.congruentProportion,
            stimulusDuration: params.stimulusDuration,
            responseTimeout: params.responseTimeout
          }))
          .setRandomization({ method: 'shuffle', constraints: ['no_more_than_3_consecutive'] })
      )
      .requirePower({ effect: 0.7, alpha: 0.05, target: 0.8 })
      .compile();
  }
});

// Register paradigm in library
ParadigmLibrary.register('stroop-task', StroopTask);
```

